mapper.select:
/* SQL ID : SmnrDAO.profSmnrListPaging 설 명 : 교수세미나목록페이징 */ WITH SBJCT_USER AS ( SELECT ATNDLC.USER_ID FROM TB_LMS_ATNDLC ATNDLC JOIN TB_LMS_SBJCT SBJCT ON ATNDLC.SBJCT_ID = SBJCT.SBJCT_ID WHERE ATNDLC.AUDITYN = 'N' AND SBJCT.SBJCT_ID = #{sbjctId} ), SUB_SMNR AS ( SELECT SMNR_ID, UP_SMNR_ID FROM TB_LMS_SMNR WHERE DELYN = 'N' AND UP_SMNR_ID IS NOT NULL ), SMNR_BASE AS ( SELECT ROW_NUMBER() OVER (ORDER BY SMNR.SMNR_SDTTM DESC, SMNR.REG_DTTM ASC) AS LINE_NO , COUNT(SMNR.SMNR_ID) OVER () AS TOTAL_CNT , SMNR.SMNR_ID , SMNR.SBJCT_ID , CASE WHEN EXISTS (SELECT 1 FROM SUB_SMNR SS WHERE SS.UP_SMNR_ID = SMNR.SMNR_ID) THEN 'SMNR_TEAM' ELSE 'SMNR' END AS SMNR_GBN , SMNR.SMNRNM , SMNR.SMNR_SDTTM , SMNR.SMNR_EDTTM , SMNR.SMNR_MNTS , SMNR.MRK_RFLTYN , SMNR.MRK_RFLTRT , SMNR.MRK_OYN , SMNR.REG_DTTM , SMNR.SMNR_GBNCD , SMNR.ATND_RCD_PFLTYN , (SELECT CDNM FROM TB_LMS_CMMN_CD WHERE UP_CD = 'SMNR_GBNCD' AND CD = SMNR.SMNR_GBNCD) AS SMNR_GBNNM , (SELECT COUNT(USER_ID) FROM SBJCT_USER) AS SMNR_TRGT_CNT , ( SELECT COUNT(ATND.SMNR_ATND_ID) FROM TB_LMS_SMNR_ATND ATND WHERE ATND.USER_ID IN (SELECT USER_ID FROM SBJCT_USER) AND ATND.SMNR_ID IN ( SELECT SS.SMNR_ID FROM SUB_SMNR SS WHERE SS.UP_SMNR_ID = SMNR.SMNR_ID UNION ALL SELECT SMNR.SMNR_ID FROM DUAL ) ) AS SMNR_ATND_CNT , ( SELECT COUNT(ATND.SMNR_ATND_ID) FROM TB_LMS_SMNR_ATND ATND WHERE ATND.USER_ID IN (SELECT USER_ID FROM SBJCT_USER) AND ATND.ATND_EVLYN = 'Y' AND ATND.SMNR_ID IN ( SELECT SS.SMNR_ID FROM SUB_SMNR SS WHERE SS.UP_SMNR_ID = SMNR.SMNR_ID UNION ALL SELECT SMNR.SMNR_ID FROM DUAL ) ) AS SMNR_EVLTEE_CNT , CASE WHEN (TO_DATE(SMNR.SMNR_SDTTM, 'YYYYMMDDHH24MISS') - SYSDATE) * 86400 <= 600 THEN 'Y' ELSE 'N' END AS SMNR_STARTYN , CASE WHEN TRUNC(TO_DATE(SMNR.SMNR_EDTTM, 'YYYYMMDDHH24MISS') + 1) - TRUNC(SYSDATE) <= 0 THEN 'Y' ELSE 'N' END AS SMNR_ENDYN , SBJCT.PROF_ID FROM TB_LMS_SMNR SMNR JOIN TB_LMS_SBJCT SBJCT ON SMNR.SBJCT_ID = SBJCT.SBJCT_ID WHERE SMNR.SMNR_TYCD = 'EDU_SMNR' AND SBJCT.SBJCT_ID = #{sbjctId} AND SMNR.DELYN = 'N' AND SMNR.UP_SMNR_ID IS NULL
AND LOWER(SMNR.SMNRNM) LIKE FN_LIKE_VAL(LOWER(#{searchValue}))
) SELECT * FROM SMNR_BASE
AND LINE_NO BETWEEN #{firstIndex} +1 AND #{firstIndex} + #{listScale}

mapper.insert:
		/*
             SQL ID : SmnrDAO.smnrRegist
             설  명 : 세미나등록
         */
        INSERT INTO TB_LMS_SMNR (
        	  SMNR_ID
			, LCTR_WKNO_SCHDL_ID
			, SBJCT_ID
			, SMNRNM
			, SMNR_CTS
			, SMNR_TYCD
			, SMNR_SDTTM
			, SMNR_EDTTM
			, SMNR_MNTS
			, SMNR_GBNCD
			, AUTO_RCDYN
			, UP_SMNR_ID
			, EVL_SCR_TYCD
			, MRK_RFLTYN
			, MRK_RFLTRT
			, MRK_OYN
			, BYTEAM_SUBSMNR_USEYN
			, RGTR_ID
			, REG_DTTM
        ) VALUES (
        	  #{smnrId}
			, #{lctrWknoSchdlId}
			, #{sbjctId}
			, #{smnrnm}
			, #{smnrCts}
			, #{smnrTycd}
			, #{smnrSdttm}
			, #{smnrEdttm}
			, #{smnrMnts}
			, #{smnrGbncd}
			, #{autoRcdyn}
			, #{upSmnrId}
			, #{evlScrTycd}
			, #{mrkRfltyn}
			, #{mrkRfltrt}
			, #{mrkOyn}
			, #{byteamSubsmnrUseyn}
			, #{rgtrId}
			, FN_DTTM()
        )

mapper.update:
    	/*
             SQL ID : SmnrDAO.smnrModify
             설  명  : 세미나수정
         */
    	UPDATE TB_LMS_SMNR SET
    		  MDFR_ID  = #{mdfrId}
    		, MOD_DTTM = FN_DTTM()

    		, LCTR_WKNO_SCHDL_ID = #{lctrWknoSchdlId}


			, SBJCT_ID = #{sbjctId}


			, SMNRNM = #{smnrnm}


			, SMNR_CTS = #{smnrCts}


			, SMNR_TYCD = #{smnrTycd}


			, SMNR_SDTTM = #{smnrSdttm}


			, SMNR_EDTTM = #{smnrEdttm}


			, SMNR_MNTS = #{smnrMnts}


			, SMNR_GBNCD = #{smnrGbncd}


			, AUTO_RCDYN = #{autoRcdyn}


			, UP_SMNR_ID = #{upSmnrId}


			, EVL_SCR_TYCD = #{evlScrTycd}


			, MRK_RFLTYN = #{mrkRfltyn}


			, MRK_RFLTRT = #{mrkRfltrt}


			, MRK_OYN = #{mrkOyn}


			, BYTEAM_SUBSMNR_USEYN = #{byteamSubsmnrUseyn}

    	WHERE SMNR_ID = #{smnrId}

	/*
         SQL ID : SmnrDAO.smnrDelynModify
         설  명  : 세미나삭제여부수정
    */
   UPDATE TB_LMS_SMNR SET
   		  MDFR_ID = #{mdfrId}
   		, MOD_DTTM = FN_DTTM()
   		, DELYN = 'Y'
   	WHERE SMNR_ID = #{smnrId}
   	   OR UP_SMNR_ID = #{smnrId}

		/*
             SQL ID : SmnrDAO.smnrMrkRfltrtListModify
             설  명 : 세미나성적반영비율목록수정
         */

	         UPDATE TB_LMS_SMNR SET
	         	  MDFR_ID = #{item.mdfrId}
	         	, MOD_DTTM = FN_DTTM()
	         	, MRK_RFLTRT = #{item.mrkRfltrt}
	          WHERE SMNR_ID = #{item.smnrId}
	            AND UP_SMNR_ID IS NULL

mapper.insert:
		/*
             SQL ID : SmnrDAO.smnrBulkRegist
             설  명 : 세미나일괄등록
         */
         INSERT ALL

			INTO TB_LMS_SMNR (
	         	  SMNR_ID
				, LCTR_WKNO_SCHDL_ID
				, SBJCT_ID
				, SMNRNM
				, SMNR_CTS
				, SMNR_TYCD
				, SMNR_SDTTM
				, SMNR_EDTTM
				, SMNR_MNTS
				, SMNR_GBNCD
				, AUTO_RCDYN
				, UP_SMNR_ID
				, EVL_SCR_TYCD
				, MRK_RFLTYN
				, MRK_RFLTRT
				, MRK_OYN
				, BYTEAM_SUBSMNR_USEYN
				, RGTR_ID
				, REG_DTTM
	         ) VALUES (
	         	  #{item.smnrId}
				, #{item.lctrWknoSchdlId}
				, #{item.sbjctId}
				, #{item.smnrnm}
				, #{item.smnrCts}
				, #{item.smnrTycd}
				, #{item.smnrSdttm}
				, #{item.smnrEdttm}
				, #{item.smnrMnts}
				, #{item.smnrGbncd}
				, #{item.autoRcdyn}
				, #{item.upSmnrId}
				, #{item.evlScrTycd}
				, #{item.mrkRfltyn}
				, #{item.mrkRfltrt}
				, #{item.mrkOyn}
				, #{item.byteamSubsmnrUseyn}
				, #{item.rgtrId}
				, FN_DTTM()
	         )

		SELECT * FROM DUAL

mapper.delete:
		/*
             SQL ID : SmnrDAO.subSmnrDelete
             설  명  : 하위세미나삭제
         */
         DELETE FROM TB_LMS_SMNR
          WHERE UP_SMNR_ID = #{smnrId}
